export const 鎮宅百鬼 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.4) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：斜圈鏈三道升列＋人字鏈
    連([0.9, 2.9], [2.4, 2.2]);
    連([2.4, 2.2], [4.4, 1.6]);
    圈(0.9, 2.9);
    圈(2.4, 2.2);
    圈(4.4, 1.6);
    連([0.9, 4.6], [2.7, 4.0]);
    連([2.7, 4.0], [4.5, 3.5]);
    圈(0.9, 4.6);
    圈(2.7, 4.0);
    圈(4.5, 3.5);
    連([0.9, 6.3], [2.5, 5.7]);
    連([2.5, 5.7], [4.4, 5.3]);
    圈(0.9, 6.3);
    圈(2.5, 5.7);
    圈(4.4, 5.3);
    連([0.9, 7.9], [2.4, 7.3]);
    連([2.4, 7.3], [4.3, 7.0]);
    圈(0.9, 7.9);
    圈(2.4, 7.3);
    圈(4.3, 7.0);
    // 寬目梯五箱
    線(p => p.M(X(0.9), Z(8.9)).L(X(0.9), Z(16.6)));
    線(p => p.M(X(4.1), Z(8.85)).L(X(4.1), Z(16.55)));
    for (let i = 0; i <= 5; i++)
        線(p => p.M(X(0.9), Z(8.9 + i * 1.54)).L(X(4.1), Z(8.85 + i * 1.54)));
    // 右柱：天無罒㬎字形疊（摹形從簡）
    線(p => p.M(X(4.9), Z(9.2)).L(X(6.5), Z(9.15)), 0.34);
    線(p => p.M(X(4.8), Z(10.0)).L(X(6.6), Z(9.95)), 0.36);
    出(p => p.M(X(5.7), Z(9.3)).C(X(5.4), Z(10.2), X(5.1), Z(10.9), X(4.7), Z(11.4)), 0.34);
    出(p => p.M(X(5.8), Z(10.3)).C(X(6.0), Z(10.8), X(6.3), Z(11.2), X(6.6), Z(11.5)), 0.34);
    // 無形（橫三豎四）
    for (const z of [12.2, 12.9, 13.6])
        線(p => p.M(X(4.7), Z(z)).L(X(6.7), Z(z - 0.04)), 0.3);
    for (const x of [5.0, 5.5, 6.0, 6.5])
        線(p => p.M(X(x), Z(12.0)).L(X(x - 0.02), Z(13.8)), 0.28);
    // 罒
    線(p => p.M(X(4.8), Z(14.4)).L(X(4.8), Z(15.4)).L(X(6.6), Z(15.35))
        .L(X(6.6), Z(14.35)).L(X(4.75), Z(14.4)), 0.32);
    線(p => p.M(X(5.4), Z(14.45)).L(X(5.38), Z(15.35)), 0.28);
    線(p => p.M(X(6.0), Z(14.4)).L(X(5.98), Z(15.3)), 0.28);
    // 㬎曲
    線(p => p.M(X(4.9), Z(15.9))
        .C(X(4.7), Z(16.5), X(4.9), Z(17.0), X(5.5), Z(17.05))
        .C(X(6.0), Z(17.1), X(6.2), Z(16.7), X(5.9), Z(16.45)), 0.34);
    // 底桁
    線(p => p.M(X(1.0), Z(17.4)).L(X(6.5), Z(17.3)), 0.42);
    線(p => p.M(X(1.0), Z(18.3)).L(X(6.5), Z(18.2)), 0.42);
};
